1	import { useMemo, useEffect, useRef } from "react";
2	import { useMarkets, useMarket, useEngineStats } from "@/lib/query/hooks";
3	import { formatProbability } from "@/lib/utils/format";
4	import { useAssumptions } from "@/features/assumptions/AssumptionContext";
5	import { useAnimationPropagation } from "./useAnimationPropagation";
6	import { deriveEdgesFromCliques, mergeEdges } from "./deriveEdges";
7	import type { MarketSummary } from "@/lib/api/types";
8	
9	interface GraphNode {
10	  id: string;
11	  title: string;
12	  x: number;
13	  y: number;
14	  marginals: Record<string, number>;
15	  outcomeName: string;
16	  status: string;
17	}
18	
19	interface GraphEdge {
20	  from: string;
21	  to: string;
22	  label?: string;
23	}
24	
25	interface BayesNetGraphProps {
26	  /** The currently viewed market — highlighted in the graph */
27	  focusMarketId?: string;
28	  /** Edges derived from conditional edits */
29	  conditionalEdges?: GraphEdge[];
30	}
31	
32	const NODE_W = 160;
33	const NODE_H = 72;
34	const PADDING = 60;
35	
36	function layoutNodes(markets: MarketSummary[]): GraphNode[] {
37	  // Arrange in a circle for small N, grid for larger
38	  const n = markets.length;
39	  if (n === 0) return [];
40	
41	  const cx = 300;
42	  const cy = 200;
43	  const radius = Math.max(120, n * 40);
44	
45	  return markets.map((m, i) => {
46	    const angle = (2 * Math.PI * i) / n - Math.PI / 2;
47	    return {
48	      id: m.id,
49	      title: m.title.length > 28 ? m.title.slice(0, 26) + "…" : m.title,
50	      x: cx + radius * Math.cos(angle),
51	      y: cy + radius * Math.sin(angle),
52	      marginals: {},
53	      outcomeName: "",
54	      status: m.status,
55	    };
56	  });
57	}
58	
59	function MarketNode({
60	  node,
61	  isFocus,
62	  detail,
63	  animationClass,
64	}: {
65	  node: GraphNode;
66	  isFocus: boolean;
67	  detail?: { marginals: Record<string, number>; outcomes: Array<{ id: string; name: string }> };
68	  animationClass?: string;
69	}) {
70	  const borderColor = isFocus ? "var(--color-primary)" : "var(--color-border)";
71	  const bg = isFocus ? "var(--color-bg-surface)" : "var(--color-bg)";
72	
73	  return (
74	    <g
75	      transform={`translate(${node.x - NODE_W / 2}, ${node.y - NODE_H / 2})`}
76	      className={animationClass}
77	    >
78	      <rect
79	        width={NODE_W}
80	        height={NODE_H}
81	        rx={8}
82	        fill={bg}
83	        stroke={borderColor}
84	        strokeWidth={isFocus ? 2.5 : 1}
85	      />
86	      <text
87	        x={NODE_W / 2}
88	        y={18}
89	        textAnchor="middle"
90	        fontSize="11"
91	        fontWeight={600}
92	        fill="var(--color-text)"
93	      >
94	        {node.title}
95	      </text>
96	      {/* Mini probability bars */}
97	      {detail && detail.outcomes.length > 0 && (
98	        <g transform="translate(8, 28)">
99	          {detail.outcomes.slice(0, 3).map((o, i) => {
100	            const p = detail.marginals[o.id] ?? 0;
101	            const barW = NODE_W - 16;
102	            return (
103	              <g key={o.id} transform={`translate(0, ${i * 14})`}>
104	                <rect width={barW} height={10} rx={3} fill="var(--color-border)" opacity={0.3} />
105	                <rect
106	                  width={Math.max(2, barW * p)}
107	                  height={10}
108	                  rx={3}
109	                  fill={animationClass ? "var(--color-info)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)"}
110	                  opacity={animationClass ? 0.9 : 0.7}
111	                  style={{ transition: "width 0.3s ease, opacity 0.3s ease, fill 0.3s ease" }}
112	                />
113	                <text x={4} y={8} fontSize="8" fill="var(--color-text)" fontWeight={500}>
114	                  {o.name}: {formatProbability(p)}
115	                </text>
116	              </g>
117	            );
118	          })}
119	        </g>
120	      )}
121	      {/* Status dot */}
122	      <circle
123	        cx={NODE_W - 10}
124	        cy={10}
125	        r={4}
126	        fill={
127	          node.status === "active"
128	            ? "var(--color-success)"
129	            : node.status === "resolved"
130	              ? "var(--color-info)"
131	              : "var(--color-text-muted)"
132	        }
133	      />
134	    </g>
135	  );
136	}
137	
138	function EdgeLine({ from, to, nodes }: { from: string; to: string; nodes: GraphNode[] }) {
139	  const a = nodes.find((n) => n.id === from);
140	  const b = nodes.find((n) => n.id === to);
141	  if (!a || !b) return null;
142	
143	  // Arrow from a → b
144	  const dx = b.x - a.x;
145	  const dy = b.y - a.y;
146	  const dist = Math.sqrt(dx * dx + dy * dy);
147	  if (dist === 0) return null;
148	
149	  const ux = dx / dist;
150	  const uy = dy / dist;
151	
152	  // Start/end offset by node radius
153	  const startX = a.x + ux * (NODE_W / 2 + 4);
154	  const startY = a.y + uy * (NODE_H / 2 + 4);
155	  const endX = b.x - ux * (NODE_W / 2 + 8);
156	  const endY = b.y - uy * (NODE_H / 2 + 8);
157	
158	  return (
159	    <g>
160	      <line
161	        x1={startX}
162	        y1={startY}
163	        x2={endX}
164	        y2={endY}
165	        stroke="var(--color-primary)"
166	        strokeWidth={1.5}
167	        strokeDasharray="6 3"
168	        opacity={0.6}
169	      />
170	      {/* Arrowhead */}
171	      <polygon
172	        points={`${endX},${endY} ${endX - ux * 8 - uy * 4},${endY - uy * 8 + ux * 4} ${endX - ux * 8 + uy * 4},${endY - uy * 8 - ux * 4}`}
173	        fill="var(--color-primary)"
174	        opacity={0.6}
175	      />
176	    </g>
177	  );
178	}
179	
180	function CliqueOverlay({
181	  clique,
182	  nodes,
183	}: {
184	  clique: { id: string; nodes: string[] };
185	  nodes: GraphNode[];
186	}) {
187	  const memberNodes = nodes.filter((n) => clique.nodes.includes(n.id));
188	  if (memberNodes.length < 2) return null;
189	
190	  // Draw a rounded rectangle around the clique members
191	  const xs = memberNodes.map((n) => n.x);
192	  const ys = memberNodes.map((n) => n.y);
193	  const pad = 20;
194	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
195	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
196	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
197	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
198	
199	  return (
200	    <g>
201	      <rect
202	        x={minX}
203	        y={minY}
204	        width={maxX - minX}
205	        height={maxY - minY}
206	        rx={12}
207	        fill="var(--color-primary)"
208	        fillOpacity={0.06}
209	        stroke="var(--color-primary)"
210	        strokeWidth={1}
211	        strokeDasharray="4 4"
212	        strokeOpacity={0.3}
213	      />
214	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
215	        Clique {clique.id}
216	      </text>
217	    </g>
218	  );
219	}
220	
221	/** Renders a mini detail-fetcher node that uses useMarket */
222	function NodeWithDetail({
223	  node,
224	  isFocus,
225	  animationClass,
226	}: {
227	  node: GraphNode;
228	  isFocus: boolean;
229	  animationClass?: string;
230	}) {
231	  const { data } = useMarket(node.id);
232	  const detail = data
233	    ? { marginals: data.market.marginals, outcomes: data.market.outcomes }
234	    : undefined;
235	  return <MarketNode node={node} isFocus={isFocus} detail={detail} animationClass={animationClass} />;
236	}
237	
238	export function BayesNetGraph({
239	  focusMarketId,
240	  conditionalEdges = [],
241	}: BayesNetGraphProps) {
242	  const { data: marketsData, isLoading } = useMarkets();
243	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
244	
245	  const markets = marketsData?.markets ?? [];
246	  const nodes = useMemo(() => layoutNodes(markets), [markets]);
247	  const cliques = engineStats?.cliques.cliques ?? [];
248	
249	  // --- Animation: detect assumption changes and trigger propagation ---
250	  const { assumptions } = useAssumptions();
251	  const { animatingNodes, animatingEdges, evidenceNodeId, triggerAnimation, cancelAnimation } =
252	    useAnimationPropagation();
253	  const prevAssumptionsRef = useRef(assumptions);
254	
255	  // Derive all edges for BFS traversal (clique-derived + conditional)
256	  const allEdges = useMemo(
257	    () => mergeEdges(deriveEdgesFromCliques(cliques), conditionalEdges),
258	    [cliques, conditionalEdges],
259	  );
260	
261	  useEffect(() => {
262	    const prev = prevAssumptionsRef.current;
263	    prevAssumptionsRef.current = assumptions;
264	
265	    if (prev === assumptions) return;
266	
267	    // Find the assumption that was added or removed
268	    const added = assumptions.find(
269	      (a) => !prev.some((p) => p.variableId === a.variableId && p.outcomeId === a.outcomeId),
270	    );
271	    const removed = prev.find(
272	      (p) => !assumptions.some((a) => a.variableId === p.variableId && a.outcomeId === p.outcomeId),
273	    );
274	
275	    const changedVariableId = added?.variableId ?? removed?.variableId;
276	    if (!changedVariableId) return;
277	
278	    // Find the node (market) that corresponds to the changed variable.
279	    // Assumption variableId may match market id (MarketSummary only has id).
280	    const evidenceNode = markets.find((m) => m.id === changedVariableId);
281	    if (evidenceNode && allEdges.length > 0) {
282	      triggerAnimation(evidenceNode.id, allEdges);
283	    }
284	  }, [assumptions, markets, allEdges, triggerAnimation]);
285	
286	  // Cancel animation on unmount
287	  useEffect(() => cancelAnimation, [cancelAnimation]);
288	
289	  if (isLoading) {
290	    return (
291	      <div style={panelStyle}>
292	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
293	          Loading network...
294	        </div>
295	      </div>
296	    );
297	  }
298	
299	  if (markets.length === 0) {
300	    return (
301	      <div style={panelStyle}>
302	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
303	          No markets to visualize.
304	        </div>
305	      </div>
306	    );
307	  }
308	
309	  // Compute SVG viewBox from node positions
310	  const xs = nodes.map((n) => n.x);
311	  const ys = nodes.map((n) => n.y);
312	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
313	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
314	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
315	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
316	
317	  return (
318	    <div style={panelStyle}>
319	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
320	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
321	          Bayesian Network
322	        </h3>
323	        <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
324	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
325	          {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
326	          {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
327	          {engineStats && ` · JT width ${engineStats.cliques.junction_tree_width}`}
328	        </div>
329	      </div>
330	
331	      <svg
332	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
333	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
334	      >
335	        <defs>
336	          {/* Glow filter for evidence node */}
337	          <filter id="evidence-glow" x="-30%" y="-30%" width="160%" height="160%">
338	            <feGaussianBlur in="SourceAlpha" stdDeviation="6" result="blur" />
339	            <feFlood floodColor="var(--color-primary)" floodOpacity="0.6" result="color" />
340	            <feComposite in="color" in2="blur" operator="in" result="glow" />
341	            <feMerge>
342	              <feMergeNode in="glow" />
343	              <feMergeNode in="SourceGraphic" />
344	            </feMerge>
345	          </filter>
346	          {/* Highlight filter for nodes reached by propagation wave */}
347	          <filter id="propagation-highlight" x="-15%" y="-15%" width="130%" height="130%">
348	            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor="var(--color-info)" floodOpacity="0.5" />
349	          </filter>
350	        </defs>
351	        <style>{`
352	          @keyframes evidence-pulse {
353	            0% { opacity: 0.7; }
354	            50% { opacity: 1; }
355	            100% { opacity: 0.7; }
356	          }
357	          @keyframes propagation-arrive {
358	            0% { opacity: 0; transform: scale(0.95); }
359	            50% { opacity: 1; transform: scale(1.02); }
360	            100% { opacity: 1; transform: scale(1); }
361	          }
362	          @keyframes edge-flow {
363	            0% { stroke-dashoffset: 16; }
364	            100% { stroke-dashoffset: 0; }
365	          }
366	          .evidence-node { animation: evidence-pulse 0.8s ease-in-out infinite; filter: url(#evidence-glow); }
367	          .propagation-node { animation: propagation-arrive 0.3s ease-out forwards; filter: url(#propagation-highlight); }
368	          .propagation-edge { animation: edge-flow 0.4s linear infinite; }
369	        `}</style>
370	
371	        {/* Clique overlays (behind edges/nodes) */}
372	        {cliques.map((c) => (
373	          <CliqueOverlay key={c.id} clique={c} nodes={nodes} />
374	        ))}
375	
376	        {/* Conditional edges */}
377	        {conditionalEdges.map((e, i) => (
378	          <EdgeLine key={`${e.from}-${e.to}-${i}`} from={e.from} to={e.to} nodes={nodes} />
379	        ))}
380	
381	        {/* Animated propagation edges */}
382	        {animatingEdges.size > 0 && allEdges.map((e) => {
383	          const ek = e.source < e.target ? `${e.source}::${e.target}` : `${e.target}::${e.source}`;
384	          if (!animatingEdges.has(ek)) return null;
385	          const a = nodes.find((n) => n.id === e.source);
386	          const b = nodes.find((n) => n.id === e.target);
387	          if (!a || !b) return null;
388	          const dx = b.x - a.x;
389	          const dy = b.y - a.y;
390	          const dist = Math.sqrt(dx * dx + dy * dy);
391	          if (dist === 0) return null;
392	          const ux = dx / dist;
393	          const uy = dy / dist;
394	          const sx = a.x + ux * (NODE_W / 2 + 4);
395	          const sy = a.y + uy * (NODE_H / 2 + 4);
396	          const ex = b.x - ux * (NODE_W / 2 + 8);
397	          const ey = b.y - uy * (NODE_H / 2 + 8);
398	          return (
399	            <line
400	              key={`anim-${ek}`}
401	              x1={sx} y1={sy} x2={ex} y2={ey}
402	              stroke="var(--color-info)"
403	              strokeWidth={2.5}
404	              strokeDasharray="8 8"
405	              opacity={0.8}
406	              className="propagation-edge"
407	            />
408	          );
409	        })}
410	
411	        {/* Market nodes */}
412	        {nodes.map((node) => {
413	          const isEvidence = node.id === evidenceNodeId;
414	          const isAnimating = animatingNodes.has(node.id);
415	          const animClass = isEvidence
416	            ? "evidence-node"
417	            : isAnimating
418	              ? "propagation-node"
419	              : undefined;
420	          return (
421	            <NodeWithDetail
422	              key={node.id}
423	              node={node}
424	              isFocus={node.id === focusMarketId}
425	              animationClass={animClass}
426	            />
427	          );
428	        })}
429	      </svg>
430	
431	      {/* Legend */}
432	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
433	        <span>
434	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
435	          Active
436	        </span>
437	        <span>
438	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-info)", marginRight: 4 }} />
439	          Resolved
440	        </span>
441	        {conditionalEdges.length > 0 && (
442	          <span>
443	            <span style={{ display: "inline-block", width: 16, height: 2, background: "var(--color-primary)", marginRight: 4, verticalAlign: "middle" }} />
444	            Conditional dependency
445	          </span>
446	        )}
447	        {cliques.length > 0 && (
448	          <span>
449	            <span style={{ display: "inline-block", width: 12, height: 12, border: "1px dashed var(--color-primary)", borderRadius: 3, marginRight: 4, verticalAlign: "middle", opacity: 0.5 }} />
450	            Junction tree clique
451	          </span>
452	        )}
453	      </div>
454	    </div>
455	  );
456	}
