6	    expect(deriveEdgesFromCliques([])).toEqual([]);
7	  });
8	
9	  it("returns no edges for single-node cliques", () => {
10	    const result = deriveEdgesFromCliques([{ id: "c1", nodes: ["a"], size: 1, states: 2 }]);
11	    expect(result).toEqual([]);
12	  });
13	
14	  it("derives edges from a 2-node clique", () => {
15	    const result = deriveEdgesFromCliques([
16	      { id: "c1", nodes: ["a", "b"], size: 2, states: 4 },
17	    ]);
18	    expect(result).toEqual([{ source: "a", target: "b" }]);
19	  });
20	
21	  it("derives all pairs from a 3-node clique", () => {
22	    const result = deriveEdgesFromCliques([
23	      { id: "c1", nodes: ["a", "b", "c"], size: 3, states: 8 },
24	    ]);
25	    expect(result).toHaveLength(3);
26	    expect(result).toEqual([
27	      { source: "a", target: "b" },
28	      { source: "a", target: "c" },
29	      { source: "b", target: "c" },
30	    ]);
31	  });
32	
33	  it("deduplicates edges across cliques", () => {
34	    const result = deriveEdgesFromCliques([
35	      { id: "c1", nodes: ["a", "b"], size: 2, states: 4 },
36	      { id: "c2", nodes: ["b", "a"], size: 2, states: 4 },
37	    ]);
38	    expect(result).toHaveLength(1);
39	  });
40	});
41	
42	describe("mergeEdges", () => {
43	  it("merges conditional edges with clique edges without duplicates", () => {
44	    const cliqueEdges = [{ source: "a", target: "b" }];
45	    const conditionalEdges = [
46	      { from: "a", to: "b" },  // duplicate
47	      { from: "c", to: "d" },  // new
48	    ];
49	    const result = mergeEdges(cliqueEdges, conditionalEdges);
50	    expect(result).toHaveLength(2);
51	    expect(result[1]).toEqual({ source: "c", target: "d" });
52	  });
53	
54	  it("handles empty conditional edges", () => {
55	    const cliqueEdges = [{ source: "a", target: "b" }];
56	    const result = mergeEdges(cliqueEdges);
57	    expect(result).toHaveLength(1);
58	  });
59	});
