238	export function BayesNetGraph({
239	  focusMarketId,
240	  conditionalEdges = [],
241	}: BayesNetGraphProps) {
242	  const { data: marketsData, isLoading } = useMarkets();
243	  const { data: engineStats } = useEngineStats(focusMarketId ?? "", { enabled: !!focusMarketId });
244	
245	  const markets = marketsData?.markets ?? [];
246	  const nodes = useMemo(() => layoutNodes(markets), [markets]);
247	  const cliques = engineStats?.cliques.cliques ?? [];
248	
249	  // --- Animation: detect assumption changes and trigger propagation ---
250	  const { assumptions } = useAssumptions();
251	  const { animatingNodes, animatingEdges, evidenceNodeId, triggerAnimation, cancelAnimation } =
252	    useAnimationPropagation();
253	  const prevAssumptionsRef = useRef(assumptions);
254	
255	  // Derive all edges for BFS traversal (clique-derived + conditional)
256	  const allEdges = useMemo(
257	    () => mergeEdges(deriveEdgesFromCliques(cliques), conditionalEdges),
258	    [cliques, conditionalEdges],
259	  );
260	
261	  useEffect(() => {
262	    const prev = prevAssumptionsRef.current;
263	    prevAssumptionsRef.current = assumptions;
264	
265	    if (prev === assumptions) return;
266	
267	    // Find the assumption that was added or removed
268	    const added = assumptions.find(
269	      (a) => !prev.some((p) => p.variableId === a.variableId && p.outcomeId === a.outcomeId),
270	    );
271	    const removed = prev.find(
272	      (p) => !assumptions.some((a) => a.variableId === p.variableId && a.outcomeId === p.outcomeId),
273	    );
274	
275	    const changedVariableId = added?.variableId ?? removed?.variableId;
276	    if (!changedVariableId) return;
277	
278	    // Find the node (market) that corresponds to the changed variable.
279	    // Assumption variableId may match market id (MarketSummary only has id).
280	    const evidenceNode = markets.find((m) => m.id === changedVariableId);
281	    if (evidenceNode && allEdges.length > 0) {
282	      triggerAnimation(evidenceNode.id, allEdges);
283	    }
284	  }, [assumptions, markets, allEdges, triggerAnimation]);
285	
286	  // Cancel animation on unmount
287	  useEffect(() => cancelAnimation, [cancelAnimation]);
288	
289	  if (isLoading) {
290	    return (
291	      <div style={panelStyle}>
292	        <div style={{ color: "var(--color-text-muted)", textAlign: "center", padding: "var(--space-lg)" }}>
293	          Loading network...
294	        </div>
295	      </div>
296	    );
297	  }
298	
299	  if (markets.length === 0) {
300	    return (
301	      <div style={panelStyle}>
302	        <div style={{ color: "var(--color-text-muted)", textAlign: "center" }}>
303	          No markets to visualize.
304	        </div>
305	      </div>
306	    );
307	  }
308	
309	  // Compute SVG viewBox from node positions
310	  const xs = nodes.map((n) => n.x);
311	  const ys = nodes.map((n) => n.y);
312	  const vbX = Math.min(...xs) - NODE_W / 2 - PADDING;
313	  const vbY = Math.min(...ys) - NODE_H / 2 - PADDING;
314	  const vbW = Math.max(...xs) - Math.min(...xs) + NODE_W + PADDING * 2;
315	  const vbH = Math.max(...ys) - Math.min(...ys) + NODE_H + PADDING * 2;
316	
317	  return (
318	    <div style={panelStyle}>
319	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "var(--space-sm)" }}>
320	        <h3 style={{ fontSize: "1rem", fontWeight: 600 }}>
321	          Bayesian Network
322	        </h3>
323	        <div style={{ fontSize: "0.75rem", color: "var(--color-text-muted)" }}>
324	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
325	          {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
326	          {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
327	          {engineStats && ` · JT width ${engineStats.cliques.junction_tree_width}`}
328	        </div>
329	      </div>
330	
331	      <svg
332	        viewBox={`${vbX} ${vbY} ${vbW} ${vbH}`}
333	        style={{ width: "100%", height: "auto", minHeight: 200, maxHeight: 400 }}
334	      >
335	        <defs>
336	          {/* Glow filter for evidence node */}
337	          <filter id="evidence-glow" x="-30%" y="-30%" width="160%" height="160%">
338	            <feGaussianBlur in="SourceAlpha" stdDeviation="6" result="blur" />
339	            <feFlood floodColor="var(--color-primary)" floodOpacity="0.6" result="color" />
340	            <feComposite in="color" in2="blur" operator="in" result="glow" />
341	            <feMerge>
342	              <feMergeNode in="glow" />
343	              <feMergeNode in="SourceGraphic" />
344	            </feMerge>
345	          </filter>
346	          {/* Highlight filter for nodes reached by propagation wave */}
347	          <filter id="propagation-highlight" x="-15%" y="-15%" width="130%" height="130%">
348	            <feDropShadow dx="0" dy="0" stdDeviation="4" floodColor="var(--color-info)" floodOpacity="0.5" />
349	          </filter>
350	        </defs>
351	        <style>{`
352	          @keyframes evidence-pulse {
353	            0% { opacity: 0.7; }
354	            50% { opacity: 1; }
355	            100% { opacity: 0.7; }
356	          }
357	          @keyframes propagation-arrive {
358	            0% { opacity: 0; transform: scale(0.95); }
359	            50% { opacity: 1; transform: scale(1.02); }
360	            100% { opacity: 1; transform: scale(1); }
361	          }
362	          @keyframes edge-flow {
363	            0% { stroke-dashoffset: 16; }
364	            100% { stroke-dashoffset: 0; }
365	          }
366	          .evidence-node { animation: evidence-pulse 0.8s ease-in-out infinite; filter: url(#evidence-glow); }
367	          .propagation-node { animation: propagation-arrive 0.3s ease-out forwards; filter: url(#propagation-highlight); }
368	          .propagation-edge { animation: edge-flow 0.4s linear infinite; }
369	        `}</style>
370	
371	        {/* Clique overlays (behind edges/nodes) */}
372	        {cliques.map((c) => (
373	          <CliqueOverlay key={c.id} clique={c} nodes={nodes} />
374	        ))}
375	
376	        {/* Conditional edges */}
377	        {conditionalEdges.map((e, i) => (
378	          <EdgeLine key={`${e.from}-${e.to}-${i}`} from={e.from} to={e.to} nodes={nodes} />
379	        ))}
380	
381	        {/* Animated propagation edges */}
382	        {animatingEdges.size > 0 && allEdges.map((e) => {
383	          const ek = e.source < e.target ? `${e.source}::${e.target}` : `${e.target}::${e.source}`;
384	          if (!animatingEdges.has(ek)) return null;
385	          const a = nodes.find((n) => n.id === e.source);
386	          const b = nodes.find((n) => n.id === e.target);
387	          if (!a || !b) return null;
388	          const dx = b.x - a.x;
389	          const dy = b.y - a.y;
390	          const dist = Math.sqrt(dx * dx + dy * dy);
391	          if (dist === 0) return null;
392	          const ux = dx / dist;
393	          const uy = dy / dist;
394	          const sx = a.x + ux * (NODE_W / 2 + 4);
395	          const sy = a.y + uy * (NODE_H / 2 + 4);
396	          const ex = b.x - ux * (NODE_W / 2 + 8);
397	          const ey = b.y - uy * (NODE_H / 2 + 8);
398	          return (
399	            <line
400	              key={`anim-${ek}`}
401	              x1={sx} y1={sy} x2={ex} y2={ey}
402	              stroke="var(--color-info)"
403	              strokeWidth={2.5}
404	              strokeDasharray="8 8"
405	              opacity={0.8}
406	              className="propagation-edge"
407	            />
408	          );
409	        })}
410	
411	        {/* Market nodes */}
412	        {nodes.map((node) => {
413	          const isEvidence = node.id === evidenceNodeId;
414	          const isAnimating = animatingNodes.has(node.id);
415	          const animClass = isEvidence
416	            ? "evidence-node"
417	            : isAnimating
418	              ? "propagation-node"
419	              : undefined;
420	          return (
421	            <NodeWithDetail
422	              key={node.id}
423	              node={node}
424	              isFocus={node.id === focusMarketId}
425	              animationClass={animClass}
426	            />
427	          );
428	        })}
429	      </svg>
430	
431	      {/* Legend */}
432	      <div style={{ display: "flex", gap: "var(--space-md)", fontSize: "0.75rem", color: "var(--color-text-muted)", marginTop: "var(--space-sm)" }}>
433	        <span>
434	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-success)", marginRight: 4 }} />
435	          Active
436	        </span>
437	        <span>
438	          <span style={{ display: "inline-block", width: 8, height: 8, borderRadius: "50%", background: "var(--color-info)", marginRight: 4 }} />
439	          Resolved
440	        </span>
441	        {conditionalEdges.length > 0 && (
442	          <span>
443	            <span style={{ display: "inline-block", width: 16, height: 2, background: "var(--color-primary)", marginRight: 4, verticalAlign: "middle" }} />
444	            Conditional dependency
445	          </span>
446	        )}
447	        {cliques.length > 0 && (
448	          <span>
449	            <span style={{ display: "inline-block", width: 12, height: 12, border: "1px dashed var(--color-primary)", borderRadius: 3, marginRight: 4, verticalAlign: "middle", opacity: 0.5 }} />
450	            Junction tree clique
451	          </span>
452	        )}
453	      </div>
454	    </div>
455	  );
456	}
457	
458	const panelStyle: React.CSSProperties = {
459	  padding: "var(--space-md)",
460	  borderRadius: "var(--radius-md)",
461	  border: "1px solid var(--color-border)",
462	  background: "var(--color-bg-surface)",
463	};
