183	function CliqueOverlay({
184	  clique,
185	  nodes,
186	}: {
187	  clique: { id: string; nodes: string[] };
188	  nodes: GraphNode[];
189	}) {
190	  const memberNodes = nodes.filter((n) => clique.nodes.includes(n.id));
191	  if (memberNodes.length < 2) return null;
192	
193	  // Draw a rounded rectangle around the clique members
194	  const xs = memberNodes.map((n) => n.x);
195	  const ys = memberNodes.map((n) => n.y);
196	  const pad = 20;
197	  const minX = Math.min(...xs) - NODE_W / 2 - pad;
198	  const minY = Math.min(...ys) - NODE_H / 2 - pad;
199	  const maxX = Math.max(...xs) + NODE_W / 2 + pad;
200	  const maxY = Math.max(...ys) + NODE_H / 2 + pad;
201	
202	  return (
203	    <g>
204	      <rect
205	        x={minX}
206	        y={minY}
207	        width={maxX - minX}
208	        height={maxY - minY}
209	        rx={12}
210	        fill="var(--color-primary)"
211	        fillOpacity={0.06}
212	        stroke="var(--color-primary)"
213	        strokeWidth={1}
214	        strokeDasharray="4 4"
215	        strokeOpacity={0.3}
216	      />
217	      <text x={minX + 6} y={minY + 14} fontSize="9" fill="var(--color-primary)" opacity={0.7}>
218	        Clique {clique.id}
219	      </text>
220	    </g>
221	  );
222	}
